INSERT INTO sentences (id, en, ko, highlight, tip, situation, cefr, topic_id, type, beats, sort_order, priority, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, ex4, ex4_ko, ex5, ex5_ko, image_keyword) VALUES
('s_academic_A1_01','Can you ~ that again?','다시 ~해 주실 수 있나요?','Can you ~ that again','이해 못했을 때 정중하게 다시 설명을 요청하는 표현이에요.','수업 중','A1','academic','pattern',NULL,1,1,'Can you explain that again, please?','다시 설명해 주실 수 있나요?','Can you explain that again more slowly?','더 천천히 다시 설명해 주실 수 있나요?','Can you explain that again with an example?','예시를 들어 다시 설명해 주실 수 있나요?','Can you explain that again in simple words?','쉬운 말로 다시 설명해 주실 수 있나요?','Can you explain that again from the beginning?','처음부터 다시 설명해 주실 수 있나요?','classroom student confused teacher explaining'),
('s_academic_A1_02','How do you ~ that ~?','그 ~을 어떻게 ~하나요?','How do you ~ that ~','단어 철자를 모를 때 물어보는 기본 표현이에요.','수업 중','A1','academic','pattern',NULL,2,1,'How do you spell that word in English?','영어로 그 단어의 철자가 어떻게 되나요?','How do you spell that word, please?','그 단어의 철자가 어떻게 되나요?','How do you spell that word — letter by letter?','한 글자씩 그 단어의 철자가 어떻게 되나요?','How do you spell that word in your language?','당신의 언어로 그 단어의 철자가 어떻게 되나요?','How do you spell that word correctly?','그 단어의 정확한 철자가 어떻게 되나요?','student writing word notebook spelling'),
('s_academic_A1_03','I don''t understand. Can you ~ more ~?','이해가 안 돼요. 더 ~하게 ~해 주실 수 있나요?','Can you ~ more ~','속도가 너무 빠를 때 정중하게 요청하는 표현이에요.','수업 중','A1','academic','pattern',NULL,3,1,'I don''t understand. Can you speak more slowly?','이해가 안 돼요. 더 천천히 말씀해 주실 수 있나요?','Can you speak more slowly, please?','더 천천히 말씀해 주실 수 있나요?','Can you speak more slowly and clearly?','더 천천히 그리고 명확하게 말씀해 주실 수 있나요?','Can you speak more slowly for me?','저를 위해 더 천천히 말씀해 주실 수 있나요?','Can you speak more slowly when explaining new words?','새 단어를 설명하실 때는 더 천천히 말씀해 주실 수 있나요?','student listening teacher classroom concentrating'),
('s_academic_A1_04','What does this ~ mean?','이 ~은 무슨 의미인가요?','What does this ~ mean','새로운 단어를 만났을 때 뜻을 묻는 가장 기본적인 표현이에요.','수업 중','A1','academic','pattern',NULL,4,1,'What does this word mean in English?','영어로 이 단어는 무슨 의미인가요?','What does this word mean in the sentence?','문장에서 이 단어는 무슨 의미인가요?','What does this word mean exactly?','이 단어는 정확히 무슨 의미인가요?','What does this word mean here?','여기서 이 단어는 무슨 의미인가요?','What does this word mean in this context?','이 맥락에서 이 단어는 무슨 의미인가요?','dictionary word lookup student desk'),
('s_academic_A1_05','May I ~?','~해도 되나요?','May I ~','수업 중에 조용히 질문 허락을 구하는 표현이에요.','수업 중','A1','academic','pattern',NULL,5,1,'May I ask a question about the homework?','숙제에 대해 질문해도 되나요?','May I ask a question before we move on?','넘어가기 전에 질문해도 되나요?','May I ask a question about chapter three?','3장에 대해 질문해도 되나요?','May I ask a question quickly?','빠르게 질문해도 되나요?','May I ask a question at the end?','마지막에 질문해도 되나요?','student raising hand classroom question'),
('s_academic_A1_06','Is this the right ~?','이게 맞는 ~인가요?','Is this the right ~','자신의 답이 맞는지 확인할 때 쓰는 표현이에요.','수업 중','A1','academic','pattern',NULL,6,1,'Is this the right answer to the problem?','이게 그 문제에 대한 맞는 답인가요?','Is this the right answer for question five?','이게 5번 문제의 맞는 답인가요?','Is this the right answer or did I make a mistake?','이게 맞는 답인가요, 아니면 제가 실수했나요?','Is this the right answer for the test?','이게 시험의 맞는 답인가요?','Is this the right answer in the textbook?','이게 교과서에 있는 맞는 답인가요?','student checking answer teacher feedback'),
('s_academic_A1_07','Please ~ it on the ~.','~에 ~해 주세요.','Please ~ it on the ~','선생님에게 칠판에 적어달라고 부탁하는 표현이에요.','수업 중','A1','academic','pattern',NULL,7,1,'Please write it on the board so we can see.','우리가 볼 수 있게 칠판에 적어 주세요.','Please write it on the board clearly.','명확하게 칠판에 적어 주세요.','Please write it on the board with the answer.','답과 함께 칠판에 적어 주세요.','Please write it on the board in big letters.','큰 글씨로 칠판에 적어 주세요.','Please write it on the board, the spelling is hard.','칠판에 적어 주세요, 철자가 어려워요.','teacher writing whiteboard chalkboard classroom'),
('s_academic_A2_01','Could you give me a ~?','~을 주실 수 있나요?','Could you give me a ~','설명을 더 잘 이해하고 싶을 때 예시를 요청하는 표현이에요.','수업·토론 중','A2','academic','pattern',NULL,1,1,'Could you give me an example of that rule?','그 규칙의 예시를 들어 주실 수 있나요?','Could you give me an example from real life?','실생활의 예시를 들어 주실 수 있나요?','Could you give me an example in a sentence?','문장 속 예시를 들어 주실 수 있나요?','Could you give me an example I can remember?','기억하기 쉬운 예시를 들어 주실 수 있나요?','Could you give me an example for the homework?','숙제 예시를 들어 주실 수 있나요?','teacher example chalkboard students lesson'),
('s_academic_A2_02','What is the main point of this ~?','이 ~의 핵심 요점은 무엇인가요?','What is the main point of this ~','글을 읽고 중심 내용을 파악할 때 쓰는 표현이에요.','독서·발표 후','A2','academic','pattern',NULL,2,1,'What is the main point of the lecture?','강의의 핵심 요점은 무엇인가요?','What is the main point of chapter two?','2장의 핵심 요점은 무엇인가요?','What is the main point of the author''s argument?','저자 주장의 핵심 요점은 무엇인가요?','What is the main point of the conclusion?','결론의 핵심 요점은 무엇인가요?','What is the main point of the study?','이 연구의 핵심 요점은 무엇인가요?','student reading article highlight study'),
('s_academic_A2_03','I think I ~, but let me check.','~한 것 같은데, 확인해 볼게요.','I think I ~, but let me check','완전히 확신하지 못할 때 겸손하게 확인하는 표현이에요.','수업·학습 중','A2','academic','pattern',NULL,3,1,'I think I understand, but let me try one more time.','이해한 것 같은데, 한 번 더 해볼게요.','I think I understand, but please clarify.','이해한 것 같은데, 명확히 해 주세요.','I think I understand the concept overall.','전체적으로 개념을 이해한 것 같아요.','I think I understand now, thank you.','이제 이해한 것 같아요, 감사해요.','I think I understand, but the second part is unclear.','이해한 것 같은데, 두 번째 부분이 명확하지 않아요.','student thinking listening lecture nodding'),
('s_academic_A2_04','Can you ~ what we ~?','우리가 ~한 것을 ~해 주실 수 있나요?','Can you ~ what we ~','수업이 끝날 때 내용을 정리하며 묻는 표현이에요.','수업 마무리','A2','academic','pattern',NULL,4,1,'Can you summarize what we discussed in class?','수업에서 토론한 것을 요약해 주실 수 있나요?','Can you summarize what we read for next week?','다음 주를 위해 읽은 것을 요약해 주실 수 있나요?','Can you summarize what we covered in the workshop?','워크숍에서 다룬 것을 요약해 주실 수 있나요?','Can you summarize what we found in the lab?','실험실에서 발견한 것을 요약해 주실 수 있나요?','Can you summarize what we agreed on?','우리가 합의한 것을 요약해 주실 수 있나요?','student summary notes writing review'),
('s_academic_A2_05','In my opinion, ~ is ~.','제 의견으로는, ~은 ~해요.','In my opinion, ~ is ~','자신의 견해를 부드럽게 제시하는 표현이에요.','토론·발표 중','A2','academic','pattern',NULL,5,1,'In my opinion, the experiment was successful.','제 의견으로는, 실험이 성공적이었어요.','In my opinion, this theory has some weaknesses.','제 의견으로는, 이 이론에는 약점이 있어요.','In my opinion, more research is needed.','제 의견으로는, 더 많은 연구가 필요해요.','In my opinion, the author makes a strong case.','제 의견으로는, 저자가 강력한 주장을 펼쳐요.','In my opinion, the data is clear.','제 의견으로는, 데이터가 명확해요.','student opinion class discussion presenting'),
('s_academic_A2_06','Where did you ~ that ~?','그 ~을 어디서 ~하셨나요?','Where did you ~ that ~','출처를 확인할 때 쓰는 표현이에요.','연구·토론 중','A2','academic','pattern',NULL,6,1,'Where did you find that information about the topic?','그 주제에 대한 정보를 어디서 찾으셨나요?','Where did you find that information online?','그 정보를 온라인 어디서 찾으셨나요?','Where did you find that information in the book?','책 어디서 그 정보를 찾으셨나요?','Where did you find that information for your paper?','논문을 위해 그 정보를 어디서 찾으셨나요?','Where did you find that information about the author?','저자에 대한 그 정보를 어디서 찾으셨나요?','student research library books computer'),
('s_academic_A2_07','Let''s ~ the ~ together.','함께 ~을 ~해 봐요.','Let''s ~ the ~ together','그룹 토론을 시작할 때 쓰는 자연스러운 표현이에요.','그룹 학습','A2','academic','pattern',NULL,7,1,'Let''s discuss the article together in groups.','함께 그룹으로 이 글을 토론해 봐요.','Let''s discuss the case study together.','함께 사례 연구를 토론해 봐요.','Let''s discuss the assignment together briefly.','함께 과제를 잠깐 토론해 봐요.','Let''s discuss the chapter together before class.','수업 전에 함께 그 챕터를 토론해 봐요.','Let''s discuss the findings together.','함께 결과를 토론해 봐요.','group students discussion seminar table'),
('s_academic_B1_01','The evidence suggests that ~.','증거는 ~을 시사해요.','The evidence suggests that ~','데이터가 이론을 뒷받침할 때 쓰는 학술적 표현이에요.','논문·발표','B1','academic','pattern',NULL,1,1,'The evidence suggests that the treatment is effective.','증거는 그 치료가 효과적이라는 것을 시사해요.','The evidence suggests that climate change is accelerating.','증거는 기후 변화가 가속화되고 있다는 것을 시사해요.','The evidence suggests that this model needs revision.','증거는 이 모델이 수정되어야 함을 시사해요.','The evidence suggests that the assumption was wrong.','증거는 그 가정이 잘못됐다는 것을 시사해요.','The evidence suggests that further investigation is required.','증거는 추가 조사가 필요함을 시사해요.','data chart research analysis academic'),
('s_academic_B1_02','Based on the ~, we can conclude that ~.','~을 바탕으로, ~라고 결론 내릴 수 있어요.','Based on the ~, we can conclude that ~','데이터 근거로 결론을 이끌어낼 때 쓰는 표현이에요.','연구 발표','B1','academic','pattern',NULL,2,1,'Based on the data, we can conclude that the intervention worked.','데이터를 바탕으로, 그 개입이 효과가 있었다고 결론 내릴 수 있어요.','Based on the data, we can conclude that more samples are needed.','데이터를 바탕으로, 더 많은 표본이 필요하다고 결론 내릴 수 있어요.','Based on the data, we can conclude that there is a strong correlation.','데이터를 바탕으로, 강한 상관관계가 있다고 결론 내릴 수 있어요.','Based on the data, we can conclude that the hypothesis is supported.','데이터를 바탕으로, 그 가설이 지지된다고 결론 내릴 수 있어요.','Based on the data, we can conclude that the trend will continue.','데이터를 바탕으로, 그 추세가 계속될 것이라고 결론 내릴 수 있어요.','researcher data analysis conclusion laptop'),
('s_academic_B1_03','This study aims to ~ the ~.','이 연구는 ~을 ~하는 것을 목표로 해요.','This study aims to ~','연구 목적을 설명할 때 쓰는 공식적인 표현이에요.','논문 서론','B1','academic','pattern',NULL,3,1,'This study aims to analyze the impact of sleep on learning.','이 연구는 수면이 학습에 미치는 영향을 분석하는 것을 목표로 해요.','This study aims to analyze the effect of social media on teens.','이 연구는 소셜 미디어가 청소년에게 미치는 영향을 분석하는 것을 목표로 해요.','This study aims to analyze the difference between groups.','이 연구는 그룹 간의 차이를 분석하는 것을 목표로 해요.','This study aims to analyze the factors that influence retention.','이 연구는 보존에 영향을 미치는 요인을 분석하는 것을 목표로 해요.','This study aims to analyze the relationship between income and health.','이 연구는 소득과 건강의 관계를 분석하는 것을 목표로 해요.','researcher lab microscope study analysis'),
('s_academic_B1_04','One limitation of this ~ is ~.','이 ~의 한 가지 한계는 ~이에요.','One limitation of this ~ is ~','연구의 약점을 솔직하게 인정하는 학술적 표현이에요.','논문 결론','B1','academic','pattern',NULL,4,1,'One limitation of this study is the lack of long-term follow-up.','이 연구의 한 가지 한계는 장기 추적이 없다는 점이에요.','One limitation of this study is the geographic scope.','이 연구의 한 가지 한계는 지리적 범위예요.','One limitation of this study is the self-reported data.','이 연구의 한 가지 한계는 자기 보고 데이터예요.','One limitation of this study is the lack of a control group.','이 연구의 한 가지 한계는 대조군이 없다는 점이에요.','One limitation of this study is the short observation period.','이 연구의 한 가지 한계는 짧은 관찰 기간이에요.','researcher contemplating data limitations notes'),
('s_academic_B1_05','~ demonstrates a significant ~.','~은 유의미한 ~을 보여줘요.','~ demonstrates a significant ~','통계적으로 유의미한 결과를 발표할 때 쓰는 표현이에요.','연구 결과 발표','B1','academic','pattern',NULL,5,1,'The results demonstrate a significant reduction in errors.','결과는 오류의 유의미한 감소를 보여줘요.','The results demonstrate a significant change in behavior.','결과는 행동의 유의미한 변화를 보여줘요.','The results demonstrate a significant gap between groups.','결과는 그룹 간 유의미한 격차를 보여줘요.','The results demonstrate a significant impact on outcomes.','결과는 결과에 미치는 유의미한 영향을 보여줘요.','The results demonstrate a significant increase in engagement.','결과는 참여도의 유의미한 증가를 보여줘요.','data graph improvement results presentation'),
('s_academic_B1_06','It is important to ~.','~하는 것이 중요해요.','It is important to ~','학술 글쓰기에서 인용의 중요성을 강조하는 표현이에요.','글쓰기 지도','B1','academic','pattern',NULL,6,1,'It is important to cite all your sources correctly to avoid plagiarism.','표절을 피하기 위해 모든 출처를 정확하게 인용하는 것이 중요해요.','It is important to cite all your sources correctly in academic papers.','학술 논문에서 모든 출처를 정확하게 인용하는 것이 중요해요.','It is important to cite all your sources correctly in the bibliography.','참고문헌에서 모든 출처를 정확하게 인용하는 것이 중요해요.','It is important to cite all your sources correctly using APA format.','APA 형식을 사용하여 모든 출처를 정확하게 인용하는 것이 중요해요.','It is important to cite all your sources correctly to maintain credibility.','신뢰성 유지를 위해 모든 출처를 정확하게 인용하는 것이 중요해요.','academic writing citations references library'),
('s_academic_B1_07','We need to consider the ~.','~을 고려해야 해요.','We need to consider the ~','연구 방법의 제약을 논의할 때 쓰는 표현이에요.','논문 심사','B1','academic','pattern',NULL,7,1,'We need to consider the ethical implications of the research.','연구의 윤리적 함의를 고려해야 해요.','We need to consider the cultural context of the participants.','참여자들의 문화적 맥락을 고려해야 해요.','We need to consider the financial constraints of the project.','프로젝트의 재정적 제약을 고려해야 해요.','We need to consider the long-term effects of the policy.','정책의 장기적 효과를 고려해야 해요.','We need to consider the practical challenges of implementation.','실행상의 실질적 어려움을 고려해야 해요.','researcher methodology notes thinking academic'),
('s_academic_B2_01','~ ~ approach was adopted to ensure both ~ and ~.','~과 ~을 모두 확보하기 위해 ~ 방법을 채택했어요.','~ ~ approach was adopted to ensure both ~ and ~','두 개의 핵심 연구 품질 지표를 동시에 다루는 표현이에요.','연구 방법 섹션','B2','academic','pattern',NULL,1,1,'A longitudinal design was adopted to ensure both validity and reliability of the findings.','결과의 타당성과 신뢰도를 모두 확보하기 위해 종단 설계를 채택했어요.','Cross-checking procedures were used to ensure both validity and reliability of the data.','데이터의 타당성과 신뢰도를 모두 확보하기 위해 교차 확인 절차를 사용했어요.','A pilot test was conducted to ensure both validity and reliability of the instrument.','도구의 타당성과 신뢰도를 모두 확보하기 위해 사전 테스트를 실시했어요.','Multiple coders were employed to ensure both validity and reliability of the analysis.','분석의 타당성과 신뢰도를 모두 확보하기 위해 여러 코더를 활용했어요.','Standardized protocols were followed to ensure both validity and reliability throughout.','전 과정에서 타당성과 신뢰도를 모두 확보하기 위해 표준화된 프로토콜을 따랐어요.','researcher reviewing data validity analysis'),
('s_academic_B2_02','The ~ were analyzed using ~.','~은 ~을 사용하여 분석되었어요.','~ were analyzed using ~','질적 연구 방법을 설명할 때 쓰는 공식 표현이에요.','연구 방법','B2','academic','pattern',NULL,2,1,'The interview transcripts were analyzed using thematic analysis.','면담 녹취록은 주제별 분석을 사용하여 분석되었어요.','The qualitative responses were analyzed using grounded theory.','질적 응답은 근거 이론을 사용하여 분석되었어요.','The open-ended survey data were analyzed using content analysis.','개방형 설문 데이터는 내용 분석을 사용하여 분석되었어요.','The narrative accounts were analyzed using discourse analysis.','서사적 진술은 담론 분석을 사용하여 분석되었어요.','The focus group transcripts were analyzed using framework analysis.','포커스 그룹 녹취록은 프레임워크 분석을 사용하여 분석되었어요.','researcher coding interviews qualitative notes'),
('s_academic_B2_03','~ must be interpreted within the ~ outlined earlier.','~은 앞서 제시한 ~ 안에서 해석되어야 해요.','~ must be interpreted within the ~','이론과 결과를 연결할 때 쓰는 학술적 표현이에요.','논문 논의','B2','academic','pattern',NULL,3,1,'The findings must be interpreted within the cultural framework of the community studied.','연구 결과는 연구된 공동체의 문화적 틀 안에서 해석되어야 해요.','The findings must be interpreted within the historical framework of the period.','연구 결과는 그 시대의 역사적 틀 안에서 해석되어야 해요.','The findings must be interpreted within the conceptual framework proposed earlier.','연구 결과는 앞서 제시한 개념적 틀 안에서 해석되어야 해요.','The findings must be interpreted within the methodological framework of the study.','연구 결과는 연구의 방법론적 틀 안에서 해석되어야 해요.','The findings must be interpreted within the broader framework of the literature.','연구 결과는 문헌의 더 넓은 틀 안에서 해석되어야 해요.','academic theory framework book scholar'),
('s_academic_B2_04','~ ensures the quality and credibility of ~.','~은 ~의 질과 신뢰성을 보장해요.','~ ensures the quality and credibility of ~','학술 출판 시스템을 설명하는 표현이에요.','연구 윤리 논의','B2','academic','pattern',NULL,4,1,'Peer review ensures the quality and rigor of published academic work.','동료 심사는 게재된 학술 작업의 질과 엄격성을 보장해요.','Peer review ensures the quality and accuracy of scientific claims.','동료 심사는 과학적 주장의 질과 정확성을 보장해요.','Peer review ensures the quality and integrity of the research process.','동료 심사는 연구 과정의 질과 무결성을 보장해요.','Peer review ensures the quality and transparency of methodology.','동료 심사는 방법론의 질과 투명성을 보장해요.','Peer review ensures the quality and originality of submitted manuscripts.','동료 심사는 제출된 원고의 질과 독창성을 보장해요.','researchers reviewing manuscript peer review'),
('s_academic_B2_05','The study operationalized the concept of ~ as ~.','연구는 ~ 개념을 ~로 조작화했어요.','operationalized the concept of ~ as ~','추상적 개념을 측정 가능하게 정의하는 방법을 설명하는 표현이에요.','연구 설계','B2','academic','pattern',NULL,5,1,'The study operationalized the concept of trust as response time to requests.','연구는 신뢰 개념을 요청에 대한 응답 시간으로 조작화했어요.','The study operationalized the concept of wellbeing as a composite score.','연구는 행복 개념을 합성 점수로 조작화했어요.','The study operationalized the concept of motivation as self-reported effort.','연구는 동기 개념을 자기 보고 노력으로 조작화했어요.','The study operationalized the concept of fluency as words per minute.','연구는 유창성 개념을 분당 단어 수로 조작화했어요.','The study operationalized the concept of social capital as network size.','연구는 사회적 자본 개념을 네트워크 규모로 조작화했어요.','researcher measuring variable data concept'),
('s_academic_B2_06','~ revealed a significant gap in ~.','~은 ~에서 상당한 공백을 드러냈어요.','~ revealed a significant gap in ~','연구의 필요성을 정당화하는 표현이에요.','논문 서론','B2','academic','pattern',NULL,6,1,'The literature review revealed a significant gap in studies on rural populations.','문헌 검토는 농촌 인구에 대한 연구에서 상당한 공백을 드러냈어요.','The literature review revealed a significant gap in longitudinal data.','문헌 검토는 종단 데이터에서 상당한 공백을 드러냈어요.','The literature review revealed a significant gap regarding minority voices.','문헌 검토는 소수자 목소리와 관련하여 상당한 공백을 드러냈어요.','The literature review revealed a significant gap in interdisciplinary work.','문헌 검토는 학제간 작업에서 상당한 공백을 드러냈어요.','The literature review revealed a significant gap in post-pandemic research.','문헌 검토는 팬데믹 이후 연구에서 상당한 공백을 드러냈어요.','academic books literature library review'),
('s_academic_B2_07','~ of ~ strengthened the credibility of ~.','~의 ~은 ~의 신뢰성을 강화했어요.','~ strengthened the credibility of','여러 데이터 출처로 결과를 검증하는 방법을 설명하는 표현이에요.','연구 방법','B2','academic','pattern',NULL,7,1,'Triangulation of methods strengthened the credibility of the conclusions.','방법의 삼각검증은 결론의 신뢰성을 강화했어요.','Triangulation of researchers strengthened the objectivity of the coding.','연구자의 삼각검증은 코딩의 객관성을 강화했어요.','Triangulation of theories strengthened the depth of the interpretation.','이론의 삼각검증은 해석의 깊이를 강화했어요.','Triangulation of timeframes strengthened the robustness of the patterns observed.','시간대의 삼각검증은 관찰된 패턴의 견고함을 강화했어요.','Triangulation of participant perspectives strengthened the validity of the analysis.','참여자 관점의 삼각검증은 분석의 타당성을 강화했어요.','researcher multiple sources triangulation data'),
('s_academic_C1_01','The ~ underlying this research privilege a ~ view of ~.','이 연구의 기저에 있는 ~은 ~에 대한 ~적 관점을 우선시해요.','The ~ underlying this research privilege','연구의 철학적 기반을 비판적으로 검토하는 표현이에요.','학술 세미나','C1','academic','pattern',NULL,1,1,'The epistemological assumptions underlying this research privilege a constructivist view of knowledge.','이 연구의 기저에 있는 인식론적 가정은 지식에 대한 구성주의적 관점을 우선시해요.','The methodological assumptions underlying this analysis privilege quantitative measurement.','이 분석의 기저에 있는 방법론적 가정은 양적 측정을 우선시해요.','The political assumptions underlying this framework privilege liberal democratic norms.','이 틀의 기저에 있는 정치적 가정은 자유민주주의 규범을 우선시해요.','The cultural assumptions underlying this model privilege Western individualist values.','이 모델의 기저에 있는 문화적 가정은 서구 개인주의적 가치를 우선시해요.','The disciplinary assumptions underlying this approach privilege a particular canon.','이 접근법의 기저에 있는 학문적 가정은 특정 정전을 우선시해요.','philosophy book scholar abstract thinking'),
('s_academic_C1_02','~ constrains the researcher''s ability to ~ ~.','~은 연구자가 ~을 ~하는 능력을 제한해요.','~ constrains the researcher''s ability to ~','연역적 방법론의 한계를 논의하는 표현이에요.','방법론 토론','C1','academic','pattern',NULL,2,1,'The inductive framework constrains the researcher''s ability to test established hypotheses.','귀납적 틀은 연구자가 확립된 가설을 검증하는 능력을 제한해요.','The positivist framework constrains the researcher''s ability to engage with subjective experience.','실증주의적 틀은 연구자가 주관적 경험을 다루는 능력을 제한해요.','The structuralist framework constrains the researcher''s ability to account for individual agency.','구조주의적 틀은 연구자가 개인의 행위자성을 설명하는 능력을 제한해요.','The neoliberal framework constrains the researcher''s ability to critique market logic.','신자유주의적 틀은 연구자가 시장 논리를 비판하는 능력을 제한해요.','The Eurocentric framework constrains the researcher''s ability to engage with diverse epistemes.','유럽 중심적 틀은 연구자가 다양한 인식 체계를 다루는 능력을 제한해요.','academic researcher framework logic notes'),
('s_academic_C1_03','~ ~ approach foregrounds the ~ of ~.','~ 접근법은 ~의 ~을 전면에 내세워요.','~ ~ approach foregrounds','현상학적 연구 방법의 핵심 특성을 설명하는 표현이에요.','연구 설계 발표','C1','academic','pattern',NULL,3,1,'A narrative approach foregrounds the storied dimensions of participants'' experiences.','서사적 접근법은 참여자 경험의 서사적 차원을 전면에 내세워요.','An ethnographic approach foregrounds the cultural meanings within the community.','민족지학적 접근법은 공동체 내의 문화적 의미를 전면에 내세워요.','A participatory approach foregrounds the voices of those traditionally marginalized.','참여적 접근법은 전통적으로 소외된 이들의 목소리를 전면에 내세워요.','A critical approach foregrounds the power relations embedded in everyday practices.','비판적 접근법은 일상적 관행에 내재된 권력 관계를 전면에 내세워요.','A decolonial approach foregrounds indigenous ways of knowing.','탈식민적 접근법은 토착민의 지식 방식을 전면에 내세워요.','philosopher contemplating phenomenology consciousness'),
('s_academic_C1_04','This paper problematizes the binary opposition between ~ and ~.','이 논문은 ~과 ~ 사이의 이분법적 대립을 문제화해요.','problematizes the binary opposition between ~ and ~','이분법적 사고를 비판적으로 다루는 학술 논문 표현이에요.','논문 서론·토론','C1','academic','pattern',NULL,4,1,'This paper problematizes the binary opposition between theory and practice.','이 논문은 이론과 실천 사이의 이분법적 대립을 문제화해요.','This paper problematizes the binary opposition between nature and culture.','이 논문은 자연과 문화 사이의 이분법적 대립을 문제화해요.','This paper problematizes the binary opposition between local and global.','이 논문은 지역적인 것과 세계적인 것 사이의 이분법적 대립을 문제화해요.','This paper problematizes the binary opposition between mind and body.','이 논문은 정신과 신체 사이의 이분법적 대립을 문제화해요.','This paper problematizes the binary opposition between public and private spheres.','이 논문은 공적 영역과 사적 영역 사이의 이분법적 대립을 문제화해요.','philosophy duality contrast scholar abstract'),
('s_academic_C1_05','~ requires the researcher to critically examine ~.','~은 연구자가 ~을 비판적으로 검토할 것을 요구해요.','~ requires the researcher to critically examine ~','질적 연구에서 성찰성의 역할을 설명하는 표현이에요.','연구 방법 발표','C1','academic','pattern',NULL,5,1,'Reflexivity requires the researcher to interrogate their assumptions throughout the process.','성찰성은 연구자가 전 과정에서 자신의 가정을 검토할 것을 요구해요.','Reflexivity requires the researcher to acknowledge their relational entanglements with participants.','성찰성은 연구자가 참여자와의 관계적 얽힘을 인정할 것을 요구해요.','Reflexivity requires the researcher to make their analytical choices transparent.','성찰성은 연구자가 분석적 선택을 투명하게 만들 것을 요구해요.','Reflexivity requires the researcher to document moments of personal discomfort.','성찰성은 연구자가 개인적 불편의 순간을 기록할 것을 요구해요.','Reflexivity requires the researcher to consider how their identity shapes the inquiry.','성찰성은 연구자가 자신의 정체성이 연구를 어떻게 형성하는지 고려할 것을 요구해요.','researcher self-reflection introspection mirror'),
('s_academic_C1_06','~ normalizes certain ~ while marginalizing others.','~은 특정 ~을 정상화하면서 다른 것들을 소외시켜요.','~ normalizes certain ~ while marginalizing others','권력과 담론의 관계를 분석하는 표현이에요.','비판 이론 세미나','C1','academic','pattern',NULL,6,1,'The hegemonic discourse normalizes certain identities while pathologizing others.','헤게모니적 담론은 특정 정체성을 정상화하면서 다른 것들을 병리화해요.','The hegemonic discourse normalizes existing inequalities as natural and inevitable.','헤게모니적 담론은 기존 불평등을 자연스럽고 필연적인 것으로 정상화해요.','The hegemonic discourse normalizes individual responsibility while obscuring structural causes.','헤게모니적 담론은 구조적 원인을 가리면서 개인의 책임을 정상화해요.','The hegemonic discourse normalizes consumption as a marker of personal worth.','헤게모니적 담론은 소비를 개인의 가치 지표로 정상화해요.','The hegemonic discourse normalizes certain knowledge claims while delegitimizing alternative epistemologies.','헤게모니적 담론은 특정 지식 주장을 정상화하면서 대안적 인식론을 탈정당화해요.','power dynamics scholarly debate discourse'),
('s_academic_C1_07','~ allows ~ to emerge inductively from ~ rather than being imposed a priori.','~은 ~이 사전에 부과되는 것이 아니라 ~에서 귀납적으로 출현하도록 해요.','emerge inductively from ~ rather than being imposed','근거 이론의 핵심 원리를 설명하는 표현이에요.','연구 방법론 강의','C1','academic','pattern',NULL,7,1,'Grounded theory allows substantive theory to emerge inductively from the data rather than being imposed in advance.','근거 이론은 실질적 이론이 사전에 부과되는 것이 아니라 데이터에서 귀납적으로 출현하도록 해요.','Grounded theory allows analytical frames to emerge inductively from the data rather than being borrowed wholesale.','근거 이론은 분석 틀이 통째로 차용되는 것이 아니라 데이터에서 귀납적으로 출현하도록 해요.','Grounded theory allows categories to emerge inductively from the data rather than being imposed a priori from the literature.','근거 이론은 범주가 문헌에서 선험적으로 부과되는 것이 아니라 데이터에서 귀납적으로 출현하도록 해요.','Grounded theory allows insights to emerge inductively from the data rather than being assumed at the outset.','근거 이론은 통찰이 시작 단계에서 가정되는 것이 아니라 데이터에서 귀납적으로 출현하도록 해요.','Grounded theory allows conceptual structures to emerge inductively from the data rather than being predetermined.','근거 이론은 개념 구조가 사전 결정되는 것이 아니라 데이터에서 귀납적으로 출현하도록 해요.','researcher data theory emerging analysis'),
('s_academic_C2_01','~''s concept of ~ destabilizes the assumption that ~.','~의 ~ 개념은 ~라는 가정을 불안정하게 해요.','~''s concept of ~ destabilizes the assumption that ~','해체론적 분석을 적용하는 고급 학술 논문 표현이에요.','철학 세미나·논문','C2','academic','pattern',NULL,1,1,'Derrida''s concept of différance destabilizes the metaphysical assumption that meaning is self-present.','데리다의 차연 개념은 의미가 자기 현존한다는 형이상학적 가정을 불안정하게 해요.','Derrida''s concept of différance destabilizes the structuralist assumption that signs operate within closed systems.','데리다의 차연 개념은 기호가 닫힌 체계 안에서 작동한다는 구조주의적 가정을 불안정하게 해요.','Derrida''s concept of différance destabilizes the phonocentric assumption that speech precedes writing.','데리다의 차연 개념은 말이 글쓰기에 앞선다는 음성중심주의적 가정을 불안정하게 해요.','Derrida''s concept of différance destabilizes the binary assumption that opposites can be cleanly separated.','데리다의 차연 개념은 대립항이 깨끗하게 분리될 수 있다는 이분법적 가정을 불안정하게 해요.','Derrida''s concept of différance destabilizes the foundationalist assumption that thought rests on stable ground.','데리다의 차연 개념은 사유가 안정된 기반 위에 있다는 토대주의적 가정을 불안정하게 해요.','philosophy book deconstruction scholar reading'),
('s_academic_C2_02','~ traces how ~ disciplines and normalizes ~.','~은 ~이 어떻게 ~을 규율하고 정상화하는지 추적해요.','~ traces how ~ disciplines and normalizes ~','푸코의 계보학적 방법을 적용한 논문 서술 방식이에요.','비판 이론 논문','C2','academic','pattern',NULL,2,1,'Foucauldian genealogy traces how the discourse of madness disciplines and normalizes deviance.','푸코적 계보학은 광기의 담론이 어떻게 일탈을 규율하고 정상화하는지 추적해요.','Foucauldian genealogy traces how the practice of confession disciplines and normalizes the modern subject.','푸코적 계보학은 고백의 실천이 어떻게 근대 주체를 규율하고 정상화하는지 추적해요.','Foucauldian genealogy traces how the clinic disciplines and normalizes bodies through medical gaze.','푸코적 계보학은 진료실이 의학적 시선을 통해 어떻게 신체를 규율하고 정상화하는지 추적해요.','Foucauldian genealogy traces how examination practices discipline and normalize student subjectivities.','푸코적 계보학은 시험 관행이 어떻게 학생 주체성을 규율하고 정상화하는지 추적해요.','Foucauldian genealogy traces how penal institutions discipline and normalize behavioral conformity.','푸코적 계보학은 형벌 기관이 어떻게 행동의 순응을 규율하고 정상화하는지 추적해요.','archive history power foucault scholar'),
('s_academic_C2_03','The ~ structure of ~ resists ~ and ~.','~의 ~적 구조는 ~과 ~에 저항해요.','The ~ structure of ~ resists ~ and ~','들뢰즈의 리좀 개념을 텍스트 분석에 적용하는 표현이에요.','문학 이론 논문','C2','academic','pattern',NULL,3,1,'The rhizomatic structure of the network resists centralization and hierarchical control.','네트워크의 리좀적 구조는 중앙 집중화와 위계적 통제에 저항해요.','The rhizomatic structure of the movement resists co-optation and disciplinary capture.','운동의 리좀적 구조는 포섭과 학문적 포획에 저항해요.','The rhizomatic structure of the archive resists linear narrative and chronological closure.','아카이브의 리좀적 구조는 선형 서사와 연대기적 종결에 저항해요.','The rhizomatic structure of the community resists representation by any single voice.','공동체의 리좀적 구조는 어떤 단일한 목소리에 의한 대표에도 저항해요.','The rhizomatic structure of the data resists categorical fixation and taxonomic order.','데이터의 리좀적 구조는 범주적 고정과 분류학적 질서에 저항해요.','network decentralized abstract connections rhizome'),
('s_academic_C2_04','~''s ~ reveals the polyphonic nature of ~ itself.','~의 ~은 ~ 자체의 다성적 특성을 드러내요.','~''s ~ reveals the polyphonic nature of ~','바흐친 이론을 담론 분석에 적용하는 표현이에요.','담론 분석 논문','C2','academic','pattern',NULL,4,1,'Bakhtin''s heteroglossia reveals the polyphonic nature of literary modernism.','바흐친의 이언론은 문학적 모더니즘의 다성적 특성을 드러내요.','Bakhtin''s heteroglossia reveals the polyphonic nature of everyday speech communities.','바흐친의 이언론은 일상 언어 공동체의 다성적 특성을 드러내요.','Bakhtin''s heteroglossia reveals the polyphonic nature of nationalist propaganda.','바흐친의 이언론은 민족주의 선전의 다성적 특성을 드러내요.','Bakhtin''s heteroglossia reveals the polyphonic nature of classroom interaction.','바흐친의 이언론은 교실 상호작용의 다성적 특성을 드러내요.','Bakhtin''s heteroglossia reveals the polyphonic nature of contested historical narratives.','바흐친의 이언론은 경합하는 역사적 서사의 다성적 특성을 드러내요.','linguistics dialogue voices academic books'),
('s_academic_C2_05','The aporia lies in the impossibility of ~ ~ within ~.','아포리아는 ~ 안에서 ~을 ~하는 것의 불가능성에 있어요.','aporia lies in the impossibility of ~ ~','포스트식민 이론의 핵심 긴장을 표현하는 고급 학술 문장이에요.','포스트식민 이론 논문','C2','academic','pattern',NULL,5,1,'The subaltern''s aporia lies in the impossibility of speaking outside the colonial archive.','서발턴의 아포리아는 식민지 아카이브 바깥에서 말하는 것의 불가능성에 있어요.','The translator''s aporia lies in the impossibility of perfect equivalence between languages.','번역자의 아포리아는 언어 간 완벽한 등가의 불가능성에 있어요.','The historian''s aporia lies in the impossibility of representing the past without imposing the present.','역사가의 아포리아는 현재를 부과하지 않고 과거를 재현하는 것의 불가능성에 있어요.','The witness''s aporia lies in the impossibility of bearing testimony to absolute trauma.','증인의 아포리아는 절대적 외상에 대한 증언의 불가능성에 있어요.','The ethnographer''s aporia lies in the impossibility of representing the other without appropriation.','민족지학자의 아포리아는 전유 없이 타자를 재현하는 것의 불가능성에 있어요.','postcolonial scholar oppression voice silence'),
('s_academic_C2_06','~''s concept of ~ explains how ~ is reproduced across generations.','~의 ~ 개념은 ~이 세대에 걸쳐 재생산되는 방식을 설명해요.','~''s concept of ~ explains how ~ is reproduced','부르디외의 핵심 개념을 연결하는 학술적 표현이에요.','사회학 이론 논문','C2','academic','pattern',NULL,6,1,'Bourdieu''s concept of habitus explains how class dispositions are reproduced through everyday gesture.','부르디외의 아비투스 개념은 계급적 성향이 일상적 몸짓을 통해 재생산되는 방식을 설명해요.','Bourdieu''s concept of habitus explains how gender norms are reproduced through embodied practice.','부르디외의 아비투스 개념은 성별 규범이 체현된 실천을 통해 재생산되는 방식을 설명해요.','Bourdieu''s concept of habitus explains how taste is reproduced as a marker of distinction.','부르디외의 아비투스 개념은 취향이 구별의 표지로 재생산되는 방식을 설명해요.','Bourdieu''s concept of habitus explains how cultural capital is reproduced across institutional fields.','부르디외의 아비투스 개념은 문화 자본이 제도적 장을 가로질러 재생산되는 방식을 설명해요.','Bourdieu''s concept of habitus explains how inequality is reproduced beneath the surface of meritocracy.','부르디외의 아비투스 개념은 불평등이 능력주의의 표면 아래에서 재생산되는 방식을 설명해요.','sociology class culture habitus scholar'),
('s_academic_C2_07','The ~ of the researcher inevitably shapes what counts as ~ within ~.','연구자의 ~은 ~ 내에서 무엇이 ~으로 인정되는지를 필연적으로 형성해요.','inevitably shapes what counts as ~','연구자의 철학적 입장이 연구 전체에 미치는 영향을 설명하는 표현이에요.','연구 방법론 논문','C2','academic','pattern',NULL,7,1,'The onto-epistemological stance of the researcher inevitably shapes what counts as data within the inquiry.','연구자의 존재-인식론적 입장은 연구 내에서 무엇이 데이터로 인정되는지를 필연적으로 형성해요.','The onto-epistemological stance of the researcher inevitably shapes how participants are positioned in the study.','연구자의 존재-인식론적 입장은 참여자들이 연구에서 어떻게 위치되는지를 필연적으로 형성해요.','The onto-epistemological stance of the researcher inevitably shapes which voices are amplified and which silenced.','연구자의 존재-인식론적 입장은 어떤 목소리가 증폭되고 어떤 목소리가 침묵되는지를 필연적으로 형성해요.','The onto-epistemological stance of the researcher inevitably shapes the analytical categories deemed meaningful.','연구자의 존재-인식론적 입장은 의미 있다고 간주되는 분석 범주를 필연적으로 형성해요.','The onto-epistemological stance of the researcher inevitably shapes the very questions that can be posed.','연구자의 존재-인식론적 입장은 제기될 수 있는 질문 자체를 필연적으로 형성해요.','philosophy researcher reflexive thinker abstract'),
('s_body_A1_01','My ~ hurts.','~가 아파요.','My ~ hurts','몸의 한 부위가 아플 때 ''부위 + hurts''로 간단히 말할 수 있어요.','통증 호소','A1','body','pattern',NULL,1,1,'My head hurts.','머리가 아파요.','My back hurts after sitting all day.','하루 종일 앉아 있었더니 허리가 아파요.','My knee hurts when I run.','달릴 때 무릎이 아파요.','My tooth hurts a lot.','이가 많이 아파요.','My foot hurts in these shoes.','이 신발을 신으면 발이 아파요.','headache head pain tired person'),
('s_body_A1_02','My ~ are cold.','제 ~가 차가워요.','My ~ are cold','신체 부위의 온도를 말할 때 ''부위 + are/is + cold''를 써요.','신체 상태','A1','body','pattern',NULL,2,1,'My feet are cold.','발이 차가워요.','My hands are cold in winter.','겨울에는 손이 차가워요.','My ears are cold without a hat.','모자를 안 쓰니 귀가 차가워요.','My fingers are cold after the walk.','산책하고 나니 손가락이 차가워요.','My toes are cold at night.','밤에는 발가락이 차가워요.','cold feet warm socks winter'),
('s_body_A1_03','Raise your ~.','~를 드세요.','Raise your ~','몸짓을 부탁하거나 지시할 때 동사로 문장을 시작해요.','제스처 지시','A1','body','pattern',NULL,3,1,'Raise your hand.','손을 드세요.','Raise your arm slowly.','팔을 천천히 드세요.','Raise your right leg.','오른쪽 다리를 드세요.','Raise your head a little.','고개를 조금 드세요.','Raise your chin up.','턱을 위로 드세요.','raise hand classroom gesture person'),
('s_body_A1_04','I''m ~.','저는 ~해요.','I''m ~','몸이 지쳤을 때 가장 기본이 되는 표현이에요.','신체 상태','A1','body','pattern',NULL,4,1,'I''m tired.','저는 피곤해요.','I''m sleepy after lunch.','점심을 먹고 나니 졸려요.','I''m hungry now.','지금 배가 고파요.','I''m thirsty after the run.','달리고 나서 목이 말라요.','I''m dizzy this morning.','오늘 아침에 어지러워요.','tired sleepy person yawning'),
('s_body_A1_05','Touch your ~.','~를 만지세요.','Touch your ~','신체 부위를 가리켜 동작을 지시할 때 ''Touch your + 부위''를 써요.','제스처 지시','A1','body','pattern',NULL,5,1,'Touch your nose.','코를 만지세요.','Touch your toes.','발끝을 만지세요.','Touch your ears.','귀를 만지세요.','Touch your knees.','무릎을 만지세요.','Touch your shoulders.','어깨를 만지세요.','touch nose finger face gesture'),
('s_body_A1_06','My ~ are dry.','제 ~가 건조해요.','My ~ are dry','눈, 피부 등이 건조할 때 ''dry''로 간단히 표현해요.','신체 상태','A1','body','pattern',NULL,6,1,'My eyes are dry.','눈이 건조해요.','My lips are dry in winter.','겨울에는 입술이 건조해요.','My hands are dry after washing.','손을 씻고 나니 손이 건조해요.','My eyes are dry from the screen.','화면을 봐서 눈이 건조해요.','My feet are dry and rough.','발이 건조하고 거칠어요.','dry eyes tired blinking person'),
('s_body_A1_07','Open your ~.','~를 여세요.','Open your ~','몸의 한 부위를 움직이도록 부탁할 때 ''Open your + 부위''를 써요.','제스처 지시','A1','body','pattern',NULL,7,1,'Open your mouth.','입을 여세요.','Open your eyes.','눈을 여세요.','Open your hand.','손을 펴세요.','Open your mouth wide.','입을 크게 벌리세요.','Open your eyes slowly.','눈을 천천히 뜨세요.','open mouth wide face person'),
('s_body_A2_01','I have a pain in my ~.','제 ~에 통증이 있어요.','I have a pain in my ~','특정 부위의 통증을 말할 때 ''a pain in my + 부위''를 자주 써요.','통증 호소','A2','body','pattern',NULL,1,1,'I have a pain in my knee.','무릎에 통증이 있어요.','I have a pain in my lower back.','허리 아래쪽에 통증이 있어요.','I have a pain in my neck.','목에 통증이 있어요.','I have a pain in my wrist.','손목에 통증이 있어요.','I have a pain in my elbow.','팔꿈치에 통증이 있어요.','knee pain leg holding joint'),
('s_body_A2_02','My ~ are stiff.','제 ~가 뻐근해요.','My ~ are stiff','몸이 뻐근할 때 ''stiff''를 써요. 어깨, 목 등에 두루 쓸 수 있어요.','신체 상태','A2','body','pattern',NULL,2,1,'My shoulders are stiff.','어깨가 뻐근해요.','My legs are stiff after the hike.','등산을 하고 나니 다리가 뻐근해요.','My fingers are stiff in the cold.','추위에 손가락이 뻣뻣해요.','My knees are stiff in the morning.','아침에는 무릎이 뻐근해요.','My arms are stiff from lifting boxes.','상자를 들었더니 팔이 뻐근해요.','stiff shoulders neck tired person'),
('s_body_A2_03','She has long, curly ~.','그녀는 길고 곱슬한 ~를 가지고 있어요.','She has long, curly ~','외모를 묘사할 때 형용사를 나열해 머리 모양을 표현해요.','외모 묘사','A2','body','pattern',NULL,3,1,'She has long, curly hair.','그녀는 길고 곱슬한 머리카락을 가지고 있어요.','She has long, curly lashes.','그녀는 길고 곱슬한 속눈썹을 가지고 있어요.','She has long, curly bangs.','그녀는 길고 곱슬한 앞머리를 가지고 있어요.','She has long, curly locks.','그녀는 길고 곱슬한 머릿단을 가지고 있어요.','She has long, curly ringlets.','그녀는 길고 곱슬한 곱슬머리를 가지고 있어요.','long curly hair woman portrait'),
('s_body_A2_04','I need to stretch my ~.','저는 ~를 스트레칭해야 해요.','I need to stretch my ~','오래 앉아 있다가 몸을 풀 때 ''stretch my legs''를 자주 써요.','몸 관리','A2','body','pattern',NULL,4,1,'I need to stretch my legs.','다리를 스트레칭해야 해요.','I need to stretch my back.','허리를 스트레칭해야 해요.','I need to stretch my neck.','목을 스트레칭해야 해요.','I need to stretch my arms.','팔을 스트레칭해야 해요.','I need to stretch my shoulders.','어깨를 스트레칭해야 해요.','stretching legs walk break person'),
